<?php
namespace App\Models;
use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\SoftDeletes;
class Card extends Model { use SoftDeletes; protected $fillable=['board_id','kanban_list_id','priority_id','assignee_id','created_by','title','description','type','status','start_date','due_date','estimated_hours','position','archived']; protected $casts=['start_date'=>'date','due_date'=>'date','archived'=>'boolean']; public function board(){return $this->belongsTo(Board::class);} public function list(){return $this->belongsTo(KanbanList::class,'kanban_list_id');} public function tags(){return $this->belongsToMany(Tag::class);} public function checklists(){return $this->hasMany(Checklist::class);} public function comments(){return $this->hasMany(Comment::class);} public function attachments(){return $this->hasMany(Attachment::class);} public function priority(){return $this->belongsTo(Priority::class);} public function assignee(){return $this->belongsTo(User::class,'assignee_id');} }
